    WHERE id = p_competition_id;

    -- Update user statistics
    UPDATE users 
    SET total_spent = total_spent + p_payment_amount,
        total_tickets = total_tickets + p_ticket_count,
        updated_at = NOW()
    WHERE id = user_id;

    RETURN new_ticket_ids;
END;
$function$

CREATE OR REPLACE FUNCTION public.purchase_tickets_with_balance(p_user_identifier text, p_competition_id text, p_ticket_price numeric, p_ticket_count integer DEFAULT NULL::integer, p_ticket_numbers integer[] DEFAULT NULL::integer[], p_idempotency_key text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_canonical_user_id TEXT; v_user_uuid TEXT; v_current_balance NUMERIC; v_total_cost NUMERIC; v_new_balance NUMERIC;
  v_final_tickets INTEGER[]; v_competition_total_tickets INTEGER; v_competition_status TEXT; v_entry_id TEXT;
  v_ticket_numbers_str TEXT; v_used_tickets INTEGER[]; v_available_tickets INTEGER[]; v_needed_count INTEGER;
  v_i INTEGER; v_random_index INTEGER; v_ticket_number INTEGER;
BEGIN
  IF p_user_identifier IS NULL OR LENGTH(TRIM(p_user_identifier)) = 0 THEN RETURN jsonb_build_object('success', false, 'error', 'User identifier is required'); END IF;
  IF p_competition_id IS NULL OR LENGTH(TRIM(p_competition_id)) = 0 THEN RETURN jsonb_build_object('success', false, 'error', 'Competition ID is required'); END IF;
  IF p_ticket_price IS NULL OR p_ticket_price <= 0 THEN RETURN jsonb_build_object('success', false, 'error', 'Ticket price must be positive'); END IF;
  IF (p_ticket_count IS NULL AND (p_ticket_numbers IS NULL OR array_length(p_ticket_numbers, 1) IS NULL)) THEN RETURN jsonb_build_object('success', false, 'error', 'Must provide either ticket_count or ticket_numbers'); END IF;

  IF p_user_identifier ~ '^0x[a-fA-F0-9]{40}$' THEN v_canonical_user_id := 'prize:pid:' || LOWER(p_user_identifier);
  ELSIF p_user_identifier LIKE 'prize:pid:%' THEN v_canonical_user_id := LOWER(p_user_identifier);
  ELSE v_canonical_user_id := 'prize:pid:' || LOWER(p_user_identifier); END IF;

  SELECT available_balance, id INTO v_current_balance, v_user_uuid FROM sub_account_balances WHERE canonical_user_id = v_canonical_user_id AND currency = 'USD' FOR UPDATE;
  IF NOT FOUND THEN
    IF p_user_identifier ~ '^0x[a-fA-F0-9]{40}$' THEN
      SELECT sab.available_balance, sab.id INTO v_current_balance, v_user_uuid FROM sub_account_balances sab
      JOIN canonical_users cu ON cu.canonical_user_id = sab.canonical_user_id
      WHERE (LOWER(cu.wallet_address) = LOWER(p_user_identifier) OR LOWER(cu.base_wallet_address) = LOWER(p_user_identifier) OR LOWER(cu.eth_wallet_address) = LOWER(p_user_identifier))
      AND sab.currency = 'USD' LIMIT 1 FOR UPDATE;
    END IF;
    IF NOT FOUND THEN RETURN jsonb_build_object('success', false, 'error', 'User balance not found', 'error_code', 'NO_BALANCE_RECORD'); END IF;
  END IF;

  SELECT total_tickets, status INTO v_competition_total_tickets, v_competition_status FROM competitions WHERE id = p_competition_id;
  IF NOT FOUND THEN RETURN jsonb_build_object('success', false, 'error', 'Competition not found'); END IF;
  IF v_competition_status != 'active' THEN RETURN jsonb_build_object('success', false, 'error', 'Competition is not active', 'competition_status', v_competition_status); END IF;

  IF p_ticket_numbers IS NOT NULL AND array_length(p_ticket_numbers, 1) > 0 THEN v_final_tickets := p_ticket_numbers;
  ELSE
    v_final_tickets := ARRAY[]::INTEGER[];
    SELECT array_agg(DISTINCT ticket_number) INTO v_used_tickets FROM tickets WHERE competition_id = p_competition_id AND ticket_number IS NOT NULL;
    v_available_tickets := ARRAY[]::INTEGER[];
    FOR v_i IN 1..v_competition_total_tickets LOOP
      IF v_used_tickets IS NULL OR NOT (v_i = ANY(v_used_tickets)) THEN v_available_tickets := array_append(v_available_tickets, v_i); END IF;
    END LOOP;
    IF array_length(v_available_tickets, 1) < p_ticket_count THEN
      RETURN jsonb_build_object('success', false, 'error', 'Not enough tickets available', 'available_count', COALESCE(array_length(v_available_tickets, 1), 0), 'requested_count', p_ticket_count);
    END IF;
    v_needed_count := p_ticket_count;
    FOR v_i IN 1..v_needed_count LOOP
      v_random_index := 1 + floor(random() * (array_length(v_available_tickets, 1) - v_i + 1))::INTEGER;
      v_ticket_number := v_available_tickets[v_random_index];
      v_final_tickets := array_append(v_final_tickets, v_ticket_number);
      v_available_tickets[v_random_index] := v_available_tickets[array_length(v_available_tickets, 1) - v_i + 1];
    END LOOP;
  END IF;

  v_total_cost := p_ticket_price * array_length(v_final_tickets, 1);
  IF v_current_balance < v_total_cost THEN RETURN jsonb_build_object('success', false, 'error', 'Insufficient balance', 'error_code', 'INSUFFICIENT_BALANCE', 'required', v_total_cost, 'available', v_current_balance); END IF;
  v_new_balance := v_current_balance - v_total_cost;

  UPDATE sub_account_balances SET available_balance = v_new_balance, updated_at = NOW() WHERE canonical_user_id = v_canonical_user_id AND currency = 'USD';

  INSERT INTO balance_ledger (canonical_user_id, transaction_type, amount, currency, balance_before, balance_after, reference_id, description, created_at)
  VALUES (v_canonical_user_id, 'debit', -v_total_cost, 'USD', v_current_balance, v_new_balance, COALESCE(p_idempotency_key, 'purchase_' || gen_random_uuid()::TEXT), 'Purchase ' || array_length(v_final_tickets, 1) || ' tickets', NOW());

  v_entry_id := gen_random_uuid()::TEXT;
  v_ticket_numbers_str := array_to_string(v_final_tickets, ',');

  BEGIN
    INSERT INTO joincompetition (uid, userid, competitionid, ticketnumbers, ticketcount, amountspent, transactionhash, createdat, updatedat)
    VALUES (v_entry_id, v_canonical_user_id, p_competition_id, v_ticket_numbers_str, array_length(v_final_tickets, 1), v_total_cost, COALESCE(p_idempotency_key, 'balance_' || v_entry_id), NOW(), NOW());
  EXCEPTION WHEN OTHERS THEN NULL; END;

  BEGIN
    INSERT INTO tickets (competition_id, ticket_number, user_id, canonical_user_id, status, created_at)
    SELECT p_competition_id, unnest(v_final_tickets), v_canonical_user_id, v_canonical_user_id, 'sold', NOW();
  EXCEPTION WHEN OTHERS THEN NULL; END;

  RETURN jsonb_build_object('success', true, 'entry_id', v_entry_id, 'ticket_numbers', v_final_tickets, 'ticket_count', array_length(v_final_tickets, 1), 'total_cost', v_total_cost, 'previous_balance', v_current_balance, 'new_balance', v_new_balance, 'competition_id', p_competition_id);
EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('success', false, 'error', 'Internal error: ' || SQLERRM, 'error_code', 'INTERNAL_ERROR');
END;
$function$

CREATE OR REPLACE FUNCTION public.release_reservation(p_reservation_id uuid, p_user_id text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_reservation RECORD;
BEGIN
  SELECT * INTO v_reservation
  FROM public.pending_tickets
  WHERE id = p_reservation_id
    AND user_id = p_user_id
  FOR UPDATE SKIP LOCKED;

  IF v_reservation IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'Reservation not found or already locked');
  END IF;

  IF v_reservation.status <> 'pending' THEN
    RETURN jsonb_build_object('success', false, 'error', 'Reservation is already ' || v_reservation.status);
  END IF;

  UPDATE public.pending_tickets
  SET status = 'cancelled',
      updated_at = NOW()
  WHERE id = p_reservation_id;

  RETURN jsonb_build_object('success', true, 'message', 'Reservation cancelled successfully');
EXCEPTION
  WHEN OTHERS THEN
    RETURN jsonb_build_object('success', false, 'error', 'Failed to cancel reservation: ' || SQLERRM);
END;
$function$

CREATE OR REPLACE FUNCTION public.repair_topup_provider_and_status()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  has_coinbase boolean := false;
  ev_id_suffix text;
  new_meta jsonb;
  new_status text;
BEGIN
  -- Only for topups; do not affect entries
  IF NEW.type <> 'topup' THEN
    RETURN NEW;
  END IF;

  -- Determine if Coinbase webhook exists for this transaction
  ev_id_suffix := NEW.id::text;

  SELECT EXISTS (
    SELECT 1
    FROM public.payment_webhook_events pwe
    WHERE pwe.provider = 'coinbase-commerce'
      AND (
        (NEW.charge_id IS NOT NULL AND pwe.transaction_id = NEW.charge_id)
        OR (pwe.event_id LIKE 'TOPUP_%_' || ev_id_suffix)
      )
  ) INTO has_coinbase;

  new_meta := COALESCE(NEW.metadata, '{}'::jsonb);

  IF has_coinbase THEN
    IF COALESCE(new_meta->>'provider', '') <> 'coinbase' THEN
      new_meta := new_meta || jsonb_build_object('provider', 'coinbase');
    END IF;
  END IF;

  -- Auto-confirm when posted_to_balance is true
  IF NEW.posted_to_balance IS TRUE THEN
    new_status := 'confirmed';
  ELSE
    new_status := COALESCE(NEW.payment_status, 'pending');
  END IF;

  IF new_meta IS DISTINCT FROM NEW.metadata OR new_status IS DISTINCT FROM NEW.payment_status THEN
    NEW.metadata := new_meta;
    NEW.payment_status := new_status;
  END IF;

  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.reserve_competition_tickets(p_user_id text, p_competition_id uuid, p_ticket_numbers integer[], p_hold_minutes integer DEFAULT 15)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_parent_id uuid := gen_random_uuid();
  v_now timestamptz := now();
  v_expires_at timestamptz := v_now + make_interval(mins => COALESCE(p_hold_minutes, 15));
  v_total integer := COALESCE(array_length(p_ticket_numbers, 1), 0);
  v_conflicts int[];
  v_inserted_count int := 0;
  v_status text;
BEGIN
  IF p_user_id IS NULL OR p_competition_id IS NULL OR v_total = 0 THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'invalid_payload',
      'message', 'user_id, competition_id and ticket_numbers[] are required'
    );
  END IF;

  SELECT status INTO v_status FROM public.competitions WHERE id = p_competition_id;
  IF v_status IS NULL OR v_status NOT IN ('active','live','running','open','ongoing') THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'competition_not_active',
      'message', 'Competition is not accepting reservations'
    );
  END IF;

  INSERT INTO public.pending_tickets (id, user_id, competition_id, status, hold_minutes, expires_at, created_at, ticket_count, ticket_price, total_amount, updated_at, ticket_numbers)
  VALUES (v_parent_id, p_user_id, p_competition_id, 'pending', COALESCE(p_hold_minutes,15), v_expires_at, v_now, v_total, NULL, NULL, v_now, NULL);

  WITH to_try AS (
    SELECT unnest(p_ticket_numbers) AS ticket_number
  ), ins AS (
    INSERT INTO public.pending_ticket_items (id, pending_ticket_id, competition_id, ticket_number, status, expires_at, created_at)
    SELECT gen_random_uuid(), v_parent_id, p_competition_id, t.ticket_number, 'pending', v_expires_at, v_now
    FROM to_try t
    ON CONFLICT (competition_id, ticket_number, expires_at) WHERE status='pending'
    DO NOTHING
    RETURNING ticket_number
  )
  SELECT COUNT(*) INTO v_inserted_count FROM ins;

  IF v_inserted_count <> v_total THEN
    SELECT ARRAY(
      SELECT t.ticket_number
      FROM (SELECT unnest(p_ticket_numbers) AS ticket_number) t
      EXCEPT
      SELECT i.ticket_number FROM public.pending_ticket_items i
      WHERE i.pending_ticket_id = v_parent_id
    ) INTO v_conflicts;

    DELETE FROM public.pending_ticket_items WHERE pending_ticket_id = v_parent_id;
    DELETE FROM public.pending_tickets WHERE id = v_parent_id;

    RETURN jsonb_build_object(
      'success', false,
      'error', 'conflict',
      'message', 'Some requested tickets are no longer available',
      'unavailableTickets', v_conflicts
    );
  END IF;

  UPDATE public.pending_tickets
  SET ticket_numbers = p_ticket_numbers, ticket_count = v_total, updated_at = now()
  WHERE id = v_parent_id;

  RETURN jsonb_build_object(
    'success', true,
    'reservationId', v_parent_id,
    'reserved', p_ticket_numbers,
    'expiresAt', v_expires_at
  );
EXCEPTION
  WHEN unique_violation THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'conflict',
      'message', 'Requested tickets are no longer available'
    );
END;
$function$

CREATE OR REPLACE FUNCTION public.reserve_selected_tickets(p_user_id text, p_competition_id uuid, p_ticket_numbers integer[], p_ticket_price numeric DEFAULT 1, p_hold_minutes integer DEFAULT 15, p_session_id text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_total_tickets integer;
  v_unavailable integer[];
  v_conflicts integer[] := ARRAY[]::integer[];
  v_clean integer[];
  v_count int;
  v_reservation_id uuid;
  v_expires_at timestamptz;
  v_total_amount numeric;
  v_inserted int;
BEGIN
  -- Validate inputs
  IF p_ticket_numbers IS NULL OR array_length(p_ticket_numbers,1) IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'No tickets provided');
  END IF;

  -- Basic competition check and lock
  SELECT total_tickets INTO v_total_tickets
  FROM competitions
  WHERE id = p_competition_id AND deleted = false AND status = 'active'
  FOR UPDATE SKIP LOCKED;

  IF v_total_tickets IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'Competition not found or locked', 'retryable', true);
  END IF;

  -- Normalize input: distinct, within range
  SELECT array_agg(DISTINCT t)
  INTO v_clean
  FROM unnest(p_ticket_numbers) t
  WHERE t BETWEEN 1 AND v_total_tickets;

  IF v_clean IS NULL OR array_length(v_clean,1) IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'No valid tickets in range');
  END IF;

  -- Build current unavailable set
  SELECT COALESCE(array_agg(ticket_number), ARRAY[]::int[])
  INTO v_unavailable
  FROM get_competition_unavailable_tickets(p_competition_id);

  -- Pre-check conflicts vs current state
  SELECT COALESCE(array_agg(t), ARRAY[]::int[])
  INTO v_conflicts
  FROM unnest(v_clean) t
  WHERE v_unavailable @> ARRAY[t];

  IF array_length(v_conflicts,1) IS NOT NULL AND array_length(v_conflicts,1) > 0 THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'Some selected tickets are unavailable',
      'status', 409,
      'unavailableTickets', v_conflicts,
      'retryable', true
    );
  END IF;

  -- Create reservation header
  v_reservation_id := gen_random_uuid();
  v_count := array_length(v_clean,1);
  v_expires_at := NOW() + make_interval(mins => LEAST(GREATEST(p_hold_minutes, 1), 60));
  v_total_amount := v_count * p_ticket_price;

  INSERT INTO pending_tickets (
    id, user_id, competition_id, ticket_numbers, ticket_count, ticket_price, total_amount,
    status, session_id, expires_at, created_at, updated_at
  ) VALUES (
    v_reservation_id, p_user_id, p_competition_id, v_clean, v_count, p_ticket_price, v_total_amount,
    'pending', p_session_id, v_expires_at, NOW(), NOW()
  );

  -- Per-ticket locking via pending_ticket_items unique partial index
  WITH ins AS (
    INSERT INTO pending_ticket_items(competition_id, pending_ticket_id, ticket_number, status, created_at, updated_at)
    SELECT p_competition_id, v_reservation_id, t, 'pending', NOW(), NOW()
    FROM unnest(v_clean) t
    ON CONFLICT DO NOTHING
    RETURNING ticket_number
  )
  SELECT COUNT(*) INTO v_inserted FROM ins;

  IF v_inserted < v_count THEN
    -- Determine which failed
    SELECT COALESCE(array_agg(t), ARRAY[]::int[])
    INTO v_conflicts
    FROM unnest(v_clean) t
    WHERE t NOT IN (
      SELECT ticket_number FROM pending_ticket_items WHERE pending_ticket_id = v_reservation_id
    );

    -- Cleanup header and any partial items
    DELETE FROM pending_ticket_items WHERE pending_ticket_id = v_reservation_id;
    DELETE FROM pending_tickets WHERE id = v_reservation_id;

    RETURN jsonb_build_object(
      'success', false,
      'error', 'Some selected tickets were claimed concurrently',
      'status', 409,
      'unavailableTickets', v_conflicts,
      'retryable', true
    );
  END IF;

  RETURN jsonb_build_object(
    'success', true,
    'reservation_id', v_reservation_id,
    'ticket_numbers', v_clean,
    'ticket_count', v_count,
    'total_amount', v_total_amount,
    'expires_at', v_expires_at
  );

EXCEPTION WHEN OTHERS THEN
  -- Cleanup on error if header exists
  IF v_reservation_id IS NOT NULL THEN
    DELETE FROM pending_ticket_items WHERE pending_ticket_id = v_reservation_id;
    DELETE FROM pending_tickets WHERE id = v_reservation_id;
  END IF;
  RETURN jsonb_build_object('success', false, 'error', 'Failed to reserve: ' || SQLERRM, 'retryable', true);
END;
$function$

CREATE OR REPLACE FUNCTION public.reserve_tickets(p_competition_id uuid, p_wallet_address text, p_ticket_count integer, p_hold_minutes integer DEFAULT 15)
 RETURNS TABLE(pending_ticket_id uuid, expires_at timestamp with time zone, ticket_numbers integer[])
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_price numeric;
  v_now timestamptz := now();
  v_pending_id uuid := gen_random_uuid();
  v_expires timestamptz := v_now + make_interval(mins => p_hold_minutes);
  v_numbers int[] := '{}';
BEGIN
  -- Validate competition and price
  SELECT ticket_price INTO v_price FROM public.competitions WHERE id = p_competition_id AND deleted = false AND status IN ('active','upcoming') LIMIT 1;
  IF NOT FOUND THEN RAISE EXCEPTION 'competition_not_available'; END IF;

  -- Create pending_tickets shell
  INSERT INTO public.pending_tickets(id, user_id, wallet_address, competition_id, status, hold_minutes, expires_at, ticket_count, ticket_price, total_amount)
  VALUES (v_pending_id, p_wallet_address, p_wallet_address, p_competition_id, 'pending', p_hold_minutes, v_expires, p_ticket_count, v_price, v_price * p_ticket_count);

  -- Pick available numbers: prefer from tickets where status='available'; otherwise allocate next numbers
  WITH avail AS (
    SELECT ticket_number FROM public.tickets
    WHERE competition_id = p_competition_id AND status = 'available'
    ORDER BY ticket_number
    LIMIT p_ticket_count
  ), fallback AS (
    SELECT generate_series(1, (SELECT total_tickets FROM public.competitions WHERE id = p_competition_id)) AS ticket_number
  ), chosen AS (
    SELECT ticket_number FROM avail
    UNION
    SELECT f.ticket_number FROM fallback f
    LEFT JOIN public.tickets t ON t.competition_id = p_competition_id AND t.ticket_number = f.ticket_number
    LEFT JOIN public.pending_ticket_items pti ON pti.competition_id = p_competition_id AND pti.ticket_number = f.ticket_number AND pti.status='pending' AND pti.expires_at > v_now
    WHERE t.id IS NULL AND pti.id IS NULL
    ORDER BY ticket_number
    LIMIT p_ticket_count
  )
  INSERT INTO public.pending_ticket_items(id, pending_ticket_id, competition_id, ticket_number, status, expires_at)
  SELECT gen_random_uuid(), v_pending_id, p_competition_id, ticket_number, 'pending', v_expires FROM chosen
  RETURNING ticket_number INTO v_numbers;

  IF array_length(v_numbers,1) IS DISTINCT FROM p_ticket_count THEN
    -- Not enough tickets; cleanup
    DELETE FROM public.pending_ticket_items WHERE pending_ticket_id = v_pending_id;
    DELETE FROM public.pending_tickets WHERE id = v_pending_id;
    RAISE EXCEPTION 'insufficient_tickets_available';
  END IF;

  RETURN QUERY SELECT v_pending_id, v_expires, v_numbers;
END; $function$

CREATE OR REPLACE FUNCTION public.resolve_canonical_identity(p_id uuid DEFAULT NULL::uuid, p_canonical_user_id text DEFAULT NULL::text, p_wallet_address text DEFAULT NULL::text, p_privy_user_id text DEFAULT NULL::text, p_email text DEFAULT NULL::text, p_username text DEFAULT NULL::text)
 RETURNS TABLE(id uuid, canonical_user_id text, wallet_address text, email text, privy_user_id text, username text, resolved_via text)
 LANGUAGE plpgsql
 STABLE
AS $function$
declare
  v_row public.canonical_users%rowtype;
begin
  -- 1) Match by internal UUID id
  if p_id is not null then
    select *
      into v_row
    from public.canonical_users cu
    where cu.id = p_id
    limit 1;

    if found then
      return query
      select v_row.id, v_row.canonical_user_id, v_row.wallet_address, v_row.email,
             v_row.privy_user_id, v_row.username, 'id'::text as resolved_via;
      return;
    end if;
  end if;

  -- 2) Match by canonical_user_id (exact)
  if p_canonical_user_id is not null then
    select *
      into v_row
    from public.canonical_users cu
    where cu.canonical_user_id = p_canonical_user_id
    limit 1;

    if found then
      return query
      select v_row.id, v_row.canonical_user_id, v_row.wallet_address, v_row.email,
             v_row.privy_user_id, v_row.username, 'canonical_user_id'::text as resolved_via;
      return;
    end if;
  end if;

  -- 3) Match by privy_user_id (exact)
  if p_privy_user_id is not null then
    select *
      into v_row
    from public.canonical_users cu
    where cu.privy_user_id = p_privy_user_id
    limit 1;

    if found then
      return query
      select v_row.id, v_row.canonical_user_id, v_row.wallet_address, v_row.email,
             v_row.privy_user_id, v_row.username, 'privy_user_id'::text as resolved_via;
      return;
    end if;
  end if;

  -- 4) Match by wallet_address (case-insensitive)
  if p_wallet_address is not null then
    select *
      into v_row
    from public.canonical_users cu
    where lower(cu.wallet_address) = lower(p_wallet_address)
    limit 1;

    if found then
      return query
      select v_row.id, v_row.canonical_user_id, v_row.wallet_address, v_row.email,
             v_row.privy_user_id, v_row.username, 'wallet_address'::text as resolved_via;
      return;
    end if;
  end if;

  -- 5) Match by email (case-insensitive)
  if p_email is not null then
    select *
      into v_row
    from public.canonical_users cu
    where lower(cu.email) = lower(p_email)
    limit 1;

    if found then
      return query
      select v_row.id, v_row.canonical_user_id, v_row.wallet_address, v_row.email,
             v_row.privy_user_id, v_row.username, 'email'::text as resolved_via;
      return;
    end if;
  end if;

  -- 6) Match by username (case-insensitive)
  if p_username is not null then
    select *
      into v_row
    from public.canonical_users cu
    where lower(cu.username) = lower(p_username)
    limit 1;

    if found then
      return query
      select v_row.id, v_row.canonical_user_id, v_row.wallet_address, v_row.email,
             v_row.privy_user_id, v_row.username, 'username'::text as resolved_via;
      return;
    end if;
  end if;

  -- If nothing matched, return no rows (NULL result)
  return;
end;
$function$

CREATE OR REPLACE FUNCTION public.resolve_canonical_user_id(input_id text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
declare
  cid text;
begin
  if input_id is null then
    return null;
  end if;

  if input_id ~ '^prize:pid:' then
    return input_id;
  end if;

  if lower(input_id) ~ '^0x[a-f0-9]{40}$' then
    select cu.canonical_user_id into cid
    from public.canonical_users cu
    where cu.wallet_address = lower(input_id)
       or cu.base_wallet_address = lower(input_id)
       or cu.eth_wallet_address = lower(input_id);

    return cid;
  end if;

  if input_id ~ '^did:privy:' then
    select cu.canonical_user_id into cid
    from public.canonical_users cu
    where cu.privy_user_id = input_id;

    return cid;
  end if;

  select cu.canonical_user_id into cid
  from public.canonical_users cu
  where cu.canonical_user_id = input_id;

  return cid;
end;
$function$

CREATE OR REPLACE FUNCTION public.resolve_or_create_canonical_user(p_canonical_user_id text)
 RETURNS canonical_users
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
declare
  u public.canonical_users;
begin
  if p_canonical_user_id is null or p_canonical_user_id !~ '^prize:pid:0x[a-f0-9]{40}$' then
    raise exception 'Invalid canonical_user_id format';
  end if;

  select * into u
  from public.canonical_users
  where canonical_user_id = p_canonical_user_id;

  if not found then
    insert into public.canonical_users (canonical_user_id)
    values (p_canonical_user_id)
    returning * into u;
  end if;

  return u;
end;
$function$

CREATE OR REPLACE FUNCTION public.rpc_debit_balance_for_order(p_order_id uuid)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_order public.orders%ROWTYPE;
  v_canon text;
  v_amount numeric;
BEGIN
  v_canon := (auth.jwt() ->> 'canonical_user_id');
  IF v_canon IS NULL THEN
    RAISE EXCEPTION 'Missing canonical_user_id claim';
  END IF;

  SELECT * INTO v_order FROM public.orders WHERE id = p_order_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Order not found';
  END IF;
  IF v_order.user_id <> v_canon THEN
    RAISE EXCEPTION 'Forbidden';
  END IF;
  IF NOT ((v_order.payment_method = 'balance' OR v_order.order_type = 'balance')
          AND (v_order.status ILIKE 'completed' OR COALESCE(v_order.payment_status,'') ILIKE 'paid%')) THEN
    RAISE EXCEPTION 'Order is not marked completed/paid via balance';
  END IF;

  v_amount := COALESCE(v_order.amount_usd, v_order.amount);
  RETURN public.debit_balance_and_confirm_tickets(
    v_canon,
    v_order.id,
    v_order.competition_id,
    v_amount,
    md5(v_order.id::text || '-balance'),
    'USD'
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.set_canonical_user_id_from_wallet()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.canonical_user_id IS NULL AND NEW.wallet_address IS NOT NULL THEN
    -- normalize wallet to lowercase
    NEW.wallet_address := lower(NEW.wallet_address);
    IF NEW.wallet_address ~ '^0x[a-f0-9]{40}$' THEN
      NEW.canonical_user_id := 'prize:pid:' || NEW.wallet_address;
    END IF;
  END IF;
  RETURN NEW;
END;$function$

CREATE OR REPLACE FUNCTION public.set_primary_wallet(user_identifier text, p_wallet_address text)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_user RECORD;
  v_normalized_address TEXT;
  v_existing_wallets JSONB;
  v_updated_wallets JSONB;
  v_wallet_found BOOLEAN := false;
  v_old_canonical_id TEXT;
  v_new_canonical_id TEXT;
BEGIN
  -- Normalize wallet address
  v_normalized_address := LOWER(p_wallet_address);

  -- Find user by various identifiers
  SELECT * INTO v_user
  FROM canonical_users cu
  WHERE cu.canonical_user_id = user_identifier
     OR LOWER(cu.wallet_address) = LOWER(user_identifier)
     OR LOWER(cu.base_wallet_address) = LOWER(user_identifier)
     OR cu.privy_user_id = user_identifier
     OR cu.email ILIKE user_identifier
     OR cu.uid::TEXT = user_identifier
  LIMIT 1;

  IF v_user IS NULL THEN
    RETURN json_build_object('success', false, 'error', 'User not found');
  END IF;

  -- Get existing wallets
  v_existing_wallets := COALESCE(v_user.linked_wallets, '[]'::JSONB);

  -- Check if wallet exists in linked_wallets or is the current base/external wallet
  SELECT EXISTS(
    SELECT 1 FROM jsonb_array_elements(v_existing_wallets) AS w
    WHERE LOWER(w->>'address') = v_normalized_address
  ) OR LOWER(v_user.base_wallet_address) = v_normalized_address
    OR LOWER(v_user.linked_external_wallet) = v_normalized_address
    OR LOWER(v_user.wallet_address) = v_normalized_address
  INTO v_wallet_found;

  IF NOT v_wallet_found THEN
    RETURN json_build_object('success', false, 'error', 'Wallet not found in account');
  END IF;

  -- Store old canonical ID for reference
  v_old_canonical_id := v_user.canonical_user_id;

  -- Generate new canonical ID based on new primary wallet
  v_new_canonical_id := 'prize:pid:' || v_normalized_address;

  -- Update is_primary flag in linked_wallets array
  SELECT jsonb_agg(
    CASE
      WHEN LOWER(w->>'address') = v_normalized_address
      THEN w || '{"is_primary": true}'::JSONB
      ELSE w || '{"is_primary": false}'::JSONB
    END
  )
  INTO v_updated_wallets
  FROM jsonb_array_elements(v_existing_wallets) AS w;

  -- Update the user record
  UPDATE canonical_users
  SET
    primary_wallet_address = v_normalized_address,
    wallet_address = v_normalized_address,
    canonical_user_id = v_new_canonical_id,
    linked_wallets = COALESCE(v_updated_wallets, v_existing_wallets),
    updated_at = NOW()
  WHERE uid = v_user.uid;

  RETURN json_build_object(
    'success', true,
    'message', 'Primary wallet updated successfully',
    'old_canonical_id', v_old_canonical_id,
    'new_canonical_id', v_new_canonical_id,
    'primary_wallet', v_normalized_address
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.sub_account_balances_sync_ids()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.user_id IS NOT NULL THEN
    NEW.user_id := 'prize:pid:' || lower(replace(NEW.user_id::text, 'prize:pid:', ''));
    NEW.canonical_user_id := NEW.user_id;
  ELSIF NEW.canonical_user_id IS NOT NULL THEN
    NEW.canonical_user_id := 'prize:pid:' || lower(replace(NEW.canonical_user_id::text, 'prize:pid:', ''));
    NEW.user_id := NEW.canonical_user_id;
  END IF;
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.sub_account_bonus_trigger()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_prev numeric := COALESCE((CASE WHEN TG_OP = 'UPDATE' THEN OLD.available_balance ELSE NULL END), 0);
  v_new numeric := COALESCE(NEW.available_balance, 0);
BEGIN
  -- Only USD rows and only when crossing strictly above 3
  IF NEW.currency = 'USD' AND v_new > 3 AND COALESCE(v_prev, 0) <= 3 THEN
    PERFORM public.award_welcome_bonus(NEW.wallet_address, 3, 100);
  END IF;
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.sync_competition_status_if_ended(p_competition_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  comp_end_date TIMESTAMPTZ;
  comp_status TEXT;
BEGIN
  SELECT status, end_date INTO comp_status, comp_end_date
  FROM competitions
  WHERE id = p_competition_id;

  IF NOT FOUND THEN
    RETURN FALSE;
  END IF;

  IF comp_status IN ('completed', 'drawn', 'cancelled') THEN
    RETURN FALSE;
  END IF;

  IF comp_end_date IS NOT NULL AND comp_end_date < NOW() THEN
    UPDATE competitions
    SET
      status = 'completed',
      updated_at = NOW()
    WHERE id = p_competition_id
      AND status IN ('active', 'drawing', 'paused');

    IF FOUND THEN
      RETURN TRUE;
    END IF;
  END IF;

  RETURN FALSE;
END;
$function$

CREATE OR REPLACE FUNCTION public.sync_external_wallet_balances(privy_user_id_param text)
 RETURNS TABLE(user_wallet_address text, external_balance numeric, previous_internal_balance numeric, new_internal_balance numeric, difference numeric)
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_user_record RECORD; v_ext NUMERIC; v_prev NUMERIC; v_new NUMERIC; BEGIN
  SELECT * INTO v_user_record FROM canonical_users WHERE privy_user_id=privy_user_id_param LIMIT 1;
  IF v_user_record IS NULL THEN RETURN; END IF;
  v_ext := 0; v_prev := COALESCE(v_user_record.usdc_balance,0); v_new := v_prev + v_ext;
  UPDATE canonical_users SET usdc_balance=v_new, updated_at=NOW() WHERE id=v_user_record.id;
  RETURN QUERY SELECT v_user_record.wallet_address, v_ext, v_prev, v_new, v_new - v_prev; END; $function$

CREATE OR REPLACE FUNCTION public.sync_identity_columns()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_row_json jsonb;
    v_canonical_user canonical_users%ROWTYPE;
    v_lookup_id text;
    v_found boolean := false;
BEGIN
    -- Convert the incoming row to JSON to check available fields
    v_row_json := to_jsonb(NEW);

    -- Only proceed if we need to fill in missing identity information
    -- Check if canonical_user_id is NULL and we have something to look up
    IF (v_row_json ? 'canonical_user_id' AND (v_row_json->>'canonical_user_id') IS NULL) OR
       (v_row_json ? 'wallet_address' AND (v_row_json->>'wallet_address') IS NULL) THEN

        -- Try lookup by canonical_user_id first (if present and not null)
        IF v_row_json ? 'canonical_user_id' AND (v_row_json->>'canonical_user_id') IS NOT NULL THEN
            v_lookup_id := v_row_json->>'canonical_user_id';
            SELECT * INTO v_canonical_user
            FROM canonical_users
            WHERE canonical_user_id = v_lookup_id
            LIMIT 1;
            v_found := FOUND;
        END IF;

        -- Try lookup by privy_user_id if not found and field exists
        IF NOT v_found AND v_row_json ? 'privy_user_id' AND (v_row_json->>'privy_user_id') IS NOT NULL THEN
            v_lookup_id := v_row_json->>'privy_user_id';
            SELECT * INTO v_canonical_user
            FROM canonical_users
            WHERE privy_user_id = v_lookup_id
            LIMIT 1;
            v_found := FOUND;
        END IF;

        -- Try lookup by user_id if not found and field exists (might be a wallet or canonical ID)
        IF NOT v_found AND v_row_json ? 'user_id' AND (v_row_json->>'user_id') IS NOT NULL THEN
            v_lookup_id := v_row_json->>'user_id';
            -- Try as canonical_user_id first
            SELECT * INTO v_canonical_user
            FROM canonical_users
            WHERE canonical_user_id = v_lookup_id
            LIMIT 1;
            v_found := FOUND;

            -- Try as wallet_address (case insensitive)
            IF NOT v_found AND v_lookup_id LIKE '0x%' THEN
                SELECT * INTO v_canonical_user
                FROM canonical_users
                WHERE LOWER(wallet_address) = LOWER(v_lookup_id)
                   OR LOWER(base_wallet_address) = LOWER(v_lookup_id)
                LIMIT 1;
                v_found := FOUND;
            END IF;

            -- Try as privy_user_id
            IF NOT v_found THEN
                SELECT * INTO v_canonical_user
                FROM canonical_users
                WHERE privy_user_id = v_lookup_id
                LIMIT 1;
                v_found := FOUND;
            END IF;

            -- Try as uid
            IF NOT v_found THEN
                SELECT * INTO v_canonical_user
                FROM canonical_users
                WHERE uid::text = v_lookup_id
                LIMIT 1;
                v_found := FOUND;
            END IF;
        END IF;

        -- Try lookup by wallet_address if not found and field exists
        IF NOT v_found AND v_row_json ? 'wallet_address' AND (v_row_json->>'wallet_address') IS NOT NULL THEN
            v_lookup_id := v_row_json->>'wallet_address';
            SELECT * INTO v_canonical_user
            FROM canonical_users
            WHERE LOWER(wallet_address) = LOWER(v_lookup_id)
               OR LOWER(base_wallet_address) = LOWER(v_lookup_id)
            LIMIT 1;
            v_found := FOUND;
        END IF;

        -- Try lookup by uid if not found and field exists
        IF NOT v_found AND v_row_json ? 'uid' AND (v_row_json->>'uid') IS NOT NULL THEN
            v_lookup_id := v_row_json->>'uid';
            SELECT * INTO v_canonical_user
            FROM canonical_users
            WHERE uid::text = v_lookup_id
            LIMIT 1;
            v_found := FOUND;
        END IF;

        -- If we found a matching canonical user, enrich the row
        IF v_found THEN
            -- Fill canonical_user_id if column exists and is NULL
            IF v_row_json ? 'canonical_user_id' AND (v_row_json->>'canonical_user_id') IS NULL THEN
                IF v_canonical_user.canonical_user_id IS NOT NULL THEN
                    NEW.canonical_user_id := v_canonical_user.canonical_user_id;
                END IF;
            END IF;

            -- Fill wallet_address if column exists and is NULL
            IF v_row_json ? 'wallet_address' AND (v_row_json->>'wallet_address') IS NULL THEN
                IF v_canonical_user.wallet_address IS NOT NULL THEN
                    NEW.wallet_address := v_canonical_user.wallet_address;
                ELSIF v_canonical_user.base_wallet_address IS NOT NULL THEN
                    NEW.wallet_address := v_canonical_user.base_wallet_address;
                END IF;
            END IF;
        END IF;
    END IF;

    RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.tickets_finalize_spend_trigger()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_finalized boolean;
  v_amount numeric;
  v_cuid text;
  v_provider text;
BEGIN
  -- Only act after insert or update to a finalized state
  v_finalized := (NEW.status IN ('sold','purchased')) AND NEW.payment_amount IS NOT NULL;
  IF NOT v_finalized THEN
    RETURN NEW;
  END IF;

  v_amount := NEW.payment_amount;
  v_cuid := public._ticket_cuid(NEW.user_id, NEW.canonical_user_id, NEW.wallet_address);
  v_provider := NEW.payment_provider; -- may be null; acceptable

  -- Ensure we only process once per ticket id
  -- Type-safe comparison: match by canonical_user_id when present, otherwise compare user_id::text
  PERFORM 1 FROM public.user_transactions ut
  WHERE ut.type = 'entry'
    AND ut.status = 'completed'
    AND ut.amount = v_amount
    AND (ut.order_id = NEW.order_id OR (NEW.order_id IS NULL AND ut.order_id IS NULL))
    AND (ut.description = NEW.id::text OR ut.description IS NULL)
    AND (
      (ut.canonical_user_id IS NOT NULL AND ut.canonical_user_id = v_cuid)
      OR (ut.canonical_user_id IS NULL AND ut.user_id IS NOT NULL AND ut.user_id::text = v_cuid)
    );
  IF FOUND THEN
    RETURN NEW;
  END IF;

  -- Insert transaction (v_cuid is canonical text id)
  PERFORM public._insert_user_spend_tx(v_cuid, v_amount, NEW.competition_id, NEW.order_id, NEW.id, v_provider, NEW.wallet_address);

  -- Deduct from balance using canonical id text
  PERFORM public._deduct_sub_account_balance(v_cuid, v_amount);

  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.tickets_sync_wallet()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.canonical_user_id IS NOT NULL AND (NEW.wallet_address IS NULL OR NEW.wallet_address = '') THEN
    NEW.wallet_address := replace(NEW.canonical_user_id, 'prize:pid:', '');
  END IF;
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.to_canonical_user_id(p_input text)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
BEGIN
  IF p_input IS NULL OR p_input = '' THEN
    RETURN NULL;
  END IF;

  -- Already canonical
  IF p_input LIKE 'prize:pid:%' THEN
    RETURN p_input;
  END IF;

  -- Privy DID
  IF p_input LIKE 'did:privy:%' THEN
    RETURN 'prize:pid:' || substring(p_input from 11);
  END IF;

  -- Wallet address
  IF p_input LIKE '0x%' THEN
    RETURN 'prize:pid:' || lower(p_input);
  END IF;

  -- Default
  RETURN 'prize:pid:' || p_input;
END;
$function$

CREATE OR REPLACE FUNCTION public.trg_sync_joincompetition_from_pending()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.transaction_hash IS NULL THEN
    RETURN NEW;
  END IF;

  -- Recompute aggregates for this tx
  PERFORM public.upsert_joincompetition_by_tx(NEW.transaction_hash);
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.trg_sync_joincompetition_from_tickets()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_old_tx text;
  v_new_tx text;
BEGIN
  IF TG_OP = 'INSERT' THEN
    v_new_tx := NEW.payment_tx_hash;
    IF v_new_tx IS NOT NULL THEN
      PERFORM public.upsert_joincompetition_by_tx(v_new_tx);
    END IF;
    RETURN NEW;
  ELSIF TG_OP = 'UPDATE' THEN
    v_old_tx := OLD.payment_tx_hash;
    v_new_tx := NEW.payment_tx_hash;
    IF v_old_tx IS NOT DISTINCT FROM v_new_tx THEN
      IF v_new_tx IS NOT NULL THEN
        PERFORM public.upsert_joincompetition_by_tx(v_new_tx);
      END IF;
    ELSE
      IF v_old_tx IS NOT NULL THEN
        PERFORM public.upsert_joincompetition_by_tx(v_old_tx);
      END IF;
      IF v_new_tx IS NOT NULL THEN
        PERFORM public.upsert_joincompetition_by_tx(v_new_tx);
      END IF;
    END IF;
    RETURN NEW;
  ELSIF TG_OP = 'DELETE' THEN
    v_old_tx := OLD.payment_tx_hash;
    IF v_old_tx IS NOT NULL THEN
      DELETE FROM public.joincompetition jc
      WHERE jc.transactionhash IS NOT DISTINCT FROM v_old_tx
        AND jc.competitionid::text = OLD.competition_id::text
        AND NOT EXISTS (
          SELECT 1 FROM public.tickets t
          WHERE t.payment_tx_hash IS NOT DISTINCT FROM v_old_tx
            AND t.competition_id = OLD.competition_id
        );
    END IF;
    RETURN OLD;
  END IF;
  RETURN NULL;
END;
$function$

