CREATE OR REPLACE FUNCTION public.unlink_external_wallet(p_canonical_user_id text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF p_canonical_user_id IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'Missing user ID');
  END IF;

  UPDATE canonical_users
  SET eth_wallet_address = NULL, updated_at = NOW()
  WHERE canonical_user_id = p_canonical_user_id OR uid = p_canonical_user_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'User not found');
  END IF;

  RETURN jsonb_build_object('success', true);
END;
$function$

CREATE OR REPLACE FUNCTION public.update_custody_balance(p_user_id text, p_amount numeric, p_transaction_type text, p_reference_id text DEFAULT NULL::text)
 RETURNS TABLE(success boolean, user_id text, balance_before numeric, balance_after numeric)
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_user_uuid UUID; v_before NUMERIC; v_after NUMERIC; BEGIN
  SELECT id INTO v_user_uuid FROM canonical_users WHERE uid=p_user_id OR wallet_address=p_user_id OR base_wallet_address=p_user_id LIMIT 1;
  IF v_user_uuid IS NULL THEN RETURN QUERY SELECT false, p_user_id, 0::NUMERIC, 0::NUMERIC; RETURN; END IF;
  SELECT COALESCE(usdc_balance,0) INTO v_before FROM canonical_users WHERE id=v_user_uuid;
  UPDATE canonical_users SET usdc_balance = v_before + p_amount, updated_at=NOW() WHERE id=v_user_uuid;
  v_after := v_before + p_amount;
  INSERT INTO custody_wallet_balances (user_id, transaction_type, change_amount, balance_before, balance_after, reference_id)
  VALUES (v_user_uuid, p_transaction_type, p_amount, v_before, v_after, p_reference_id);
  RETURN QUERY SELECT true, v_user_uuid::TEXT, v_before, v_after; END; $function$

