CREATE OR REPLACE FUNCTION public.update_profile_flex(payload jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_identifier text := COALESCE(
    payload->>'identifier', payload->>'user_identifier', payload->>'canonical_user_id',
    payload->>'p_identifier', payload->>'p_canonical_user_id', payload->>'email'
  );
  v_username text := COALESCE(payload->>'username', payload->>'p_username');
  v_email text := COALESCE(payload->>'email', payload->>'p_email');
  v_phone text := COALESCE(payload->>'phone', payload->>'telephone', payload->>'telephone_number', payload->>'p_phone');
  v_country text := COALESCE(payload->>'country', payload->>'p_country');
  v_telegram text := payload->>'telegram_handle';
  v_telnum text := COALESCE(payload->>'telephone_number', payload->>'p_telephone_number');
BEGIN
  IF v_identifier IS NULL THEN
    RAISE EXCEPTION 'missing_identifier' USING MESSAGE = 'identifier (canonical_user_id or email) is required';
  END IF;
  RETURN public.update_user_profile_by_identifier(v_identifier, v_username, v_email, v_phone, v_country, v_telegram, v_telnum);
END; $function$

CREATE OR REPLACE FUNCTION public.update_wallet_nickname(user_identifier text, p_wallet_address text, p_nickname text)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_user RECORD;
  v_normalized_address TEXT;
  v_existing_wallets JSONB;
  v_updated_wallets JSONB;
BEGIN
  v_normalized_address := LOWER(p_wallet_address);

  -- Find user
  SELECT * INTO v_user
  FROM canonical_users cu
  WHERE cu.canonical_user_id = user_identifier
     OR LOWER(cu.wallet_address) = LOWER(user_identifier)
     OR cu.privy_user_id = user_identifier
     OR cu.email ILIKE user_identifier
     OR cu.uid::TEXT = user_identifier
  LIMIT 1;

  IF v_user IS NULL THEN
    RETURN json_build_object('success', false, 'error', 'User not found');
  END IF;

  v_existing_wallets := COALESCE(v_user.linked_wallets, '[]'::JSONB);

  -- Update the nickname for the specified wallet
  SELECT jsonb_agg(
    CASE
      WHEN LOWER(w->>'address') = v_normalized_address
      THEN jsonb_set(w, '{nickname}', to_jsonb(p_nickname))
      ELSE w
    END
  )
  INTO v_updated_wallets
  FROM jsonb_array_elements(v_existing_wallets) AS w;

  UPDATE canonical_users
  SET
    linked_wallets = COALESCE(v_updated_wallets, v_existing_wallets),
    updated_at = NOW()
  WHERE uid = v_user.uid;

  RETURN json_build_object('success', true, 'message', 'Nickname updated successfully');
END;
$function$

CREATE OR REPLACE FUNCTION public.upsert_canonical_user_by_username(p_username text, p_email text DEFAULT NULL::text, p_country text DEFAULT NULL::text, p_canonical_user_id text DEFAULT NULL::text, p_wallet_address text DEFAULT NULL::text, p_base_wallet_address text DEFAULT NULL::text, p_eth_wallet_address text DEFAULT NULL::text, p_avatar_url text DEFAULT NULL::text, p_first_name text DEFAULT NULL::text, p_last_name text DEFAULT NULL::text, p_telegram_handle text DEFAULT NULL::text, p_privy_user_id text DEFAULT NULL::text, p_uid uuid DEFAULT NULL::uuid)
 RETURNS canonical_users
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_row public.canonical_users;
  v_id uuid;
BEGIN
  -- 1) Lookup by username first (your source of truth)
  IF p_username IS NOT NULL THEN
    SELECT * INTO v_row FROM public.canonical_users WHERE username = p_username;
  END IF;

  -- 2) Fallback by email
  IF v_row.id IS NULL AND p_email IS NOT NULL THEN
    SELECT * INTO v_row FROM public.canonical_users WHERE email = p_email;
  END IF;

  -- 3) Fallback by canonical_user_id
  IF v_row.id IS NULL AND p_canonical_user_id IS NOT NULL THEN
    SELECT * INTO v_row FROM public.canonical_users WHERE canonical_user_id = p_canonical_user_id;
  END IF;

  -- 4) Insert if not found
  IF v_row.id IS NULL THEN
    v_id := COALESCE(p_uid, gen_random_uuid());
    INSERT INTO public.canonical_users AS cu (
      id, username, email, country, canonical_user_id,
      wallet_address, base_wallet_address, eth_wallet_address,
      avatar_url, first_name, last_name, telegram_handle, privy_user_id
    ) VALUES (
      v_id, p_username, p_email, p_country, p_canonical_user_id,
      p_wallet_address, p_base_wallet_address, p_eth_wallet_address,
      p_avatar_url, p_first_name, p_last_name, p_telegram_handle, p_privy_user_id
    )
    RETURNING * INTO v_row;
    RETURN v_row;
  END IF;

  -- 5) Merge non-null fields only
  UPDATE public.canonical_users cu
  SET
    username            = COALESCE(p_username, cu.username),
    email               = COALESCE(p_email, cu.email),
    country             = COALESCE(p_country, cu.country),
    canonical_user_id   = COALESCE(p_canonical_user_id, cu.canonical_user_id),
    wallet_address      = COALESCE(p_wallet_address, cu.wallet_address),
    base_wallet_address = COALESCE(p_base_wallet_address, cu.base_wallet_address),
    eth_wallet_address  = COALESCE(p_eth_wallet_address, cu.eth_wallet_address),
    avatar_url          = COALESCE(p_avatar_url, cu.avatar_url),
    first_name          = COALESCE(p_first_name, cu.first_name),
    last_name           = COALESCE(p_last_name, cu.last_name),
    telegram_handle     = COALESCE(p_telegram_handle, cu.telegram_handle),
    privy_user_id       = COALESCE(p_privy_user_id, cu.privy_user_id),
    updated_at          = NOW()
  WHERE cu.id = v_row.id
  RETURNING * INTO v_row;

  RETURN v_row;
END;
$function$

CREATE OR REPLACE FUNCTION public.user_transactions_post_to_wallet()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_delta numeric;
  v_before numeric;
  v_after numeric;
  v_curr text;
  v_desc text;
BEGIN
  -- Only act when status = completed and not yet posted
  IF NEW.status <> 'completed' OR COALESCE(NEW.posted_to_balance, false) IS TRUE THEN
    RETURN NEW;
  END IF;

  IF NEW.amount IS NULL OR NEW.amount <= 0 THEN
    RAISE EXCEPTION 'Amount must be positive';
  END IF;

  -- CRITICAL FIX: Skip external crypto payments
  IF NEW.payment_provider IN (
    'base_account',
    'coinbase_commerce',
    'coinbase',
    'privy_base_wallet',
    'onchainkit',
    'onchainkit_checkout'
  ) THEN
    NEW.posted_to_balance := true;
    NEW.completed_at := COALESCE(NEW.completed_at, now());
    RETURN NEW;
  END IF;

  -- ONLY process balance payments and onramp top-ups
  IF NEW.payment_provider NOT IN ('balance', 'onramp', 'coinbase_onramp') THEN
    NEW.posted_to_balance := true;
    NEW.completed_at := COALESCE(NEW.completed_at, now());
    RETURN NEW;
  END IF;

  v_curr := COALESCE(NEW.currency, 'USDC');
  v_delta := public._wallet_delta_from_txn(NEW.type, NEW.amount);

  -- Apply to wallet
  SELECT balance_before, balance_after
    INTO v_before, v_after
  FROM public._apply_wallet_delta(NEW.canonical_user_id, v_curr, v_delta);

  -- Compose description
  v_desc := COALESCE(NEW.description,
            CASE WHEN lower(NEW.type) IN ('topup','top_up','top-up') THEN 'Wallet top up'
                 WHEN lower(NEW.type) IN ('entry','entry_payment','purchase') THEN 'Competition entry'
                 ELSE 'User transaction'
            END);

  -- Insert ledger row
  INSERT INTO public.balance_ledger (
    canonical_user_id,
    transaction_type,
    amount,
    currency,
    balance_before,
    balance_after,
    reference_id,
    description,
    created_at,
    top_up_tx_id
  ) VALUES (
    NEW.canonical_user_id,
    NEW.type,
    NEW.amount,
    v_curr,
    v_before,
    v_after,
    NEW.id::text,
    v_desc,
    now(),
    COALESCE(NEW.tx_id, NEW.payment_tx_hash)
  );

  NEW.posted_to_balance := true;
  NEW.completed_at := COALESCE(NEW.completed_at, now());
  RETURN NEW;
END;
$function$

