CREATE OR REPLACE FUNCTION realtime.broadcast_changes(topic_name text, event_name text, operation text, table_name text, table_schema text, new record, old record, level text DEFAULT 'ROW'::text)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    -- Declare a variable to hold the JSONB representation of the row
    row_data jsonb := '{}'::jsonb;
BEGIN
    IF level = 'STATEMENT' THEN
        RAISE EXCEPTION 'function can only be triggered for each row, not for each statement';
    END IF;
    -- Check the operation type and handle accordingly
    IF operation = 'INSERT' OR operation = 'UPDATE' OR operation = 'DELETE' THEN
        row_data := jsonb_build_object('old_record', OLD, 'record', NEW, 'operation', operation, 'table', table_name, 'schema', table_schema);
        PERFORM realtime.send (row_data, event_name, topic_name);
    ELSE
        RAISE EXCEPTION 'Unexpected operation type: %', operation;
    END IF;
EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'Failed to process the row: %', SQLERRM;
END;

$function$

CREATE OR REPLACE FUNCTION realtime.send(payload jsonb, event text, topic text, private boolean DEFAULT true)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  generated_id uuid;
  final_payload jsonb;
BEGIN
  BEGIN
    -- Generate a new UUID for the id
    generated_id := gen_random_uuid();

    -- Check if payload has an 'id' key, if not, add the generated UUID
    IF payload ? 'id' THEN
      final_payload := payload;
    ELSE
      final_payload := jsonb_set(payload, '{id}', to_jsonb(generated_id));
    END IF;

    -- Set the topic configuration
    EXECUTE format('SET LOCAL realtime.topic TO %L', topic);

    -- Attempt to insert the message
    INSERT INTO realtime.messages (id, payload, event, topic, private, extension)
    VALUES (generated_id, final_payload, event, topic, private, 'broadcast');
  EXCEPTION
    WHEN OTHERS THEN
      -- Capture and notify the error
      RAISE WARNING 'ErrorSendingBroadcastMessage: %', SQLERRM;
  END;
END;
$function$

CREATE OR REPLACE FUNCTION realtime.subscription_check_filters()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
    /*
    Validates that the user defined filters for a subscription:
    - refer to valid columns that the claimed role may access
    - values are coercable to the correct column type
    */
    declare
        col_names text[] = coalesce(
                array_agg(c.column_name order by c.ordinal_position),
                '{}'::text[]
            )
            from
                information_schema.columns c
            where
                format('%I.%I', c.table_schema, c.table_name)::regclass = new.entity
                and pg_catalog.has_column_privilege(
                    (new.claims ->> 'role'),
                    format('%I.%I', c.table_schema, c.table_name)::regclass,
                    c.column_name,
                    'SELECT'
                );
        filter realtime.user_defined_filter;
        col_type regtype;

        in_val jsonb;
    begin
        for filter in select * from unnest(new.filters) loop
            -- Filtered column is valid
            if not filter.column_name = any(col_names) then
                raise exception 'invalid column for filter %', filter.column_name;
            end if;

            -- Type is sanitized and safe for string interpolation
            col_type = (
                select atttypid::regtype
                from pg_catalog.pg_attribute
                where attrelid = new.entity
                      and attname = filter.column_name
            );
            if col_type is null then
                raise exception 'failed to lookup type for column %', filter.column_name;
            end if;

            -- Set maximum number of entries for in filter
            if filter.op = 'in'::realtime.equality_op then
                in_val = realtime.cast(filter.value, (col_type::text || '[]')::regtype);
                if coalesce(jsonb_array_length(in_val), 0) > 100 then
                    raise exception 'too many values for `in` filter. Maximum 100';
                end if;
            else
                -- raises an exception if value is not coercable to type
                perform realtime.cast(filter.value, col_type);
            end if;

        end loop;

        -- Apply consistent order to filters so the unique constraint on
        -- (subscription_id, entity, filters) can't be tricked by a different filter order
        new.filters = coalesce(
            array_agg(f order by f.column_name, f.op, f.value),
            '{}'
        ) from unnest(new.filters) f;

        return new;
    end;
    $function$

CREATE OR REPLACE FUNCTION util.finalize_pending_user_transactions()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_curr_balance numeric;
BEGIN
  IF NEW.status = 'pending' THEN
    SELECT COALESCE(sab.available_balance, 0)
      INTO v_curr_balance
      FROM public.sub_account_balances sab
     WHERE sab.canonical_user_id = NEW.canonical_user_id
       AND sab.currency = NEW.currency
     LIMIT 1;

    NEW.balance_before := COALESCE(v_curr_balance, 0);
    NEW.balance_after  := COALESCE(v_curr_balance, 0) + COALESCE(NEW.amount, 0);
    NEW.status := 'completed';
    NEW.completed_at := NOW();
    NEW.posted_to_balance := true;

    -- Upsert balance atomically
    INSERT INTO public.sub_account_balances (
      user_id, canonical_user_id, currency, available_balance, pending_balance, last_updated
    ) VALUES (
      NEW.user_id, NEW.canonical_user_id, NEW.currency, COALESCE(NEW.amount,0), 0, NOW()
    )
    ON CONFLICT (canonical_user_id, currency)
    DO UPDATE SET available_balance = public.sub_account_balances.available_balance + EXCLUDED.available_balance,
                  last_updated = NOW();
  END IF;

  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION util.resolve_canonical_user_id(p_wallet text, p_privy text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
AS $function$
    DECLARE
      v_wallet text := util.normalize_wallet(p_wallet);
      v_cuid text;
    BEGIN
      IF v_wallet IS NOT NULL THEN
        SELECT cu.canonical_user_id
        INTO v_cuid
        FROM public.canonical_users cu
        WHERE v_wallet = ANY(ARRAY[
          cu.wallet_address,
          cu.base_wallet_address,
          cu.eth_wallet_address,
          cu.primary_wallet_address
        ])
        LIMIT 1;
        IF v_cuid IS NOT NULL THEN
          RETURN v_cuid;
        END IF;

        SELECT cu.canonical_user_id
        INTO v_cuid
        FROM public.canonical_users cu
        WHERE cu.linked_wallets ? v_wallet
        LIMIT 1;
        IF v_cuid IS NOT NULL THEN
          RETURN v_cuid;
        END IF;
      END IF;

      IF p_privy IS NOT NULL THEN
        SELECT cu.canonical_user_id
        INTO v_cuid
        FROM public.canonical_users cu
        WHERE cu.privy_user_id = p_privy
        LIMIT 1;
        IF v_cuid IS NOT NULL THEN
          RETURN v_cuid;
        END IF;
      END IF;

      RETURN NULL;
    END;
    $function$

CREATE OR REPLACE FUNCTION util.trg_set_cuid_from_context()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.canonical_user_id IS NULL THEN
    NEW.canonical_user_id := util.resolve_canonical_user_id(
      NEW.wallet_address,
      COALESCE(NEW.privy_user_id, NEW.user_privy_id)
    );
  END IF;
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION util.upsert_canonical_user_from_auth(in_p_canonical_id text, in_p_wallet_address text, in_p_email text, in_p_auth_provider text DEFAULT NULL::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_id uuid;
  v_wallet text := util.normalize_evm_address(in_p_wallet_address);
  v_email text := NULLIF(lower(trim(in_p_email)), '');
  v_canon text := CASE 
    WHEN in_p_canonical_id IS NOT NULL AND length(trim(in_p_canonical_id))>0 THEN lower(trim(in_p_canonical_id))
    WHEN v_wallet IS NOT NULL THEN 'prize:pid:' || v_wallet
    ELSE NULL
  END;
BEGIN
  -- Optional small delay to let client events settle
  PERFORM pg_sleep(2);

  -- Try canonical id first
  IF v_canon IS NOT NULL THEN
    SELECT id INTO v_id FROM public.canonical_users WHERE canonical_user_id = v_canon LIMIT 1;
    IF FOUND THEN
      UPDATE public.canonical_users SET
        wallet_address = COALESCE(wallet_address, v_wallet),
        base_wallet_address = COALESCE(base_wallet_address, v_wallet),
        eth_wallet_address = COALESCE(eth_wallet_address, v_wallet),
        email = COALESCE(email, v_email),
        auth_provider = COALESCE(auth_provider, in_p_auth_provider),
        wallet_linked = COALESCE(wallet_linked, (v_wallet IS NOT NULL)),
        updated_at = NOW()
      WHERE id = v_id;
      RETURN v_id;
    END IF;
  END IF;

  -- Try wallet next
  IF v_wallet IS NOT NULL THEN
    SELECT id INTO v_id FROM public.canonical_users WHERE wallet_address = v_wallet LIMIT 1;
    IF FOUND THEN
      UPDATE public.canonical_users SET
        canonical_user_id = COALESCE(canonical_user_id, v_canon),
        email = COALESCE(email, v_email),
        auth_provider = COALESCE(auth_provider, in_p_auth_provider),
        wallet_linked = COALESCE(wallet_linked, true),
        updated_at = NOW()
      WHERE id = v_id;
      RETURN v_id;
    END IF;
  END IF;

  -- Try email last (case-insensitive)
  IF v_email IS NOT NULL THEN
    SELECT id INTO v_id FROM public.canonical_users WHERE lower(email) = v_email LIMIT 1;
    IF FOUND THEN
      UPDATE public.canonical_users SET
        canonical_user_id = COALESCE(canonical_user_id, v_canon),
        wallet_address = COALESCE(wallet_address, v_wallet),
        base_wallet_address = COALESCE(base_wallet_address, v_wallet),
        eth_wallet_address = COALESCE(eth_wallet_address, v_wallet),
        auth_provider = COALESCE(auth_provider, in_p_auth_provider),
        wallet_linked = COALESCE(wallet_linked, (v_wallet IS NOT NULL)),
        updated_at = NOW()
      WHERE id = v_id;
      RETURN v_id;
    END IF;
  END IF;

  -- Insert new if none found. Enforce canonical id and wallet normalization.
  INSERT INTO public.canonical_users (
    id, canonical_user_id, uid, email, wallet_address, base_wallet_address, eth_wallet_address, auth_provider, wallet_linked
  ) VALUES (
    gen_random_uuid(), v_canon, gen_random_uuid(), v_email, v_wallet, v_wallet, v_wallet, in_p_auth_provider, (v_wallet IS NOT NULL)
  )
  ON CONFLICT (canonical_user_id) DO UPDATE SET
    email = COALESCE(public.canonical_users.email, EXCLUDED.email),
    wallet_address = COALESCE(public.canonical_users.wallet_address, EXCLUDED.wallet_address),
    base_wallet_address = COALESCE(public.canonical_users.base_wallet_address, EXCLUDED.base_wallet_address),
    eth_wallet_address = COALESCE(public.canonical_users.eth_wallet_address, EXCLUDED.eth_wallet_address),
    auth_provider = COALESCE(public.canonical_users.auth_provider, EXCLUDED.auth_provider),
    wallet_linked = COALESCE(public.canonical_users.wallet_linked, EXCLUDED.wallet_linked),
    updated_at = NOW()
  RETURNING id INTO v_id;

  RETURN v_id;
END;
$function$

CREATE OR REPLACE FUNCTION util.uuid_from_text(p_input text)
 RETURNS uuid
 LANGUAGE plpgsql
 STABLE
AS $function$
declare
  ns uuid := '6ba7b811-9dad-11d1-80b4-00c04fd430c8'; -- DNS namespace as base
  hash bytea;
  bytes bytea;
begin
  if p_input is null or length(p_input) = 0 then
    return null;
  end if;
  -- v5 uuid = sha1(namespace || name)
  hash := digest(convert_to(ns::text || p_input, 'utf8'), 'sha1');
  bytes := substring(hash from 1 for 16);
  -- set version (0101 for v5) and variant (10xx)
  bytes := set_bit(bytes, 52, 1); -- version bit 52..55 -> 0101; set 52 and 54
  bytes := set_bit(bytes, 53, 0);
  bytes := set_bit(bytes, 54, 1);
  bytes := set_bit(bytes, 55, 0);
  bytes := set_bit(bytes, 64, 1); -- variant bits 64..65 -> 10
  bytes := set_bit(bytes, 65, 0);
  bytes := set_bit(bytes, 66, get_bit(bytes,66));
  bytes := set_bit(bytes, 67, get_bit(bytes,67));
  return (
    lpad(to_hex(get_byte(bytes,0)),2,'0') ||
    lpad(to_hex(get_byte(bytes,1)),2,'0') ||
    lpad(to_hex(get_byte(bytes,2)),2,'0') ||
    lpad(to_hex(get_byte(bytes,3)),2,'0') || '-' ||
    lpad(to_hex(get_byte(bytes,4)),2,'0') ||
    lpad(to_hex(get_byte(bytes,5)),2,'0') || '-' ||
    lpad(to_hex(get_byte(bytes,6)),2,'0') ||
    lpad(to_hex(get_byte(bytes,7)),2,'0') || '-' ||
    lpad(to_hex(get_byte(bytes,8)),2,'0') ||
    lpad(to_hex(get_byte(bytes,9)),2,'0') || '-' ||
    lpad(to_hex(get_byte(bytes,10)),2,'0') ||
    lpad(to_hex(get_byte(bytes,11)),2,'0') ||
    lpad(to_hex(get_byte(bytes,12)),2,'0') ||
    lpad(to_hex(get_byte(bytes,13)),2,'0') ||
    lpad(to_hex(get_byte(bytes,14)),2,'0') ||
    lpad(to_hex(get_byte(bytes,15)),2,'0')
  )::uuid;
end;
$function$
